import time
import ubinascii
import machine
import network
from umqtt.simple import MQTTClient

WIFI_SSID = "YOUR_WIFI_SSID"
WIFI_PASSWORD = "YOUR_WIFI_PASSWORD"

BROKER_IP = "192.168.1.10"
TOPIC_TEMP = b"sensors/temp"

PUBLISH_INTERVAL_S = 5


def wifi_connect(ssid, password, timeout_s=20):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        wlan.connect(ssid, password)
        t0 = time.ticks_ms()
        while not wlan.isconnected():
            if time.ticks_diff(time.ticks_ms(), t0) > timeout_s * 1000:
                raise RuntimeError("WiFi connect timeout")
            time.sleep_ms(200)
    return wlan


def read_temperature_c():
    try:
        from esp32 import raw_temperature
        return float(raw_temperature())
    except Exception:
        pass

    try:
        adc = machine.ADC(machine.Pin(34))
        adc.atten(machine.ADC.ATTN_11DB)
        adc.width(machine.ADC.WIDTH_12BIT)
        v = adc.read() / 4095.0 * 3.3
        return 20.0 + (v - 1.65) * 10.0
    except Exception:
        return 0.0


def make_client_id():
    return b"esp32-" + ubinascii.hexlify(machine.unique_id())


def main():
    wifi_connect(WIFI_SSID, WIFI_PASSWORD)

    client = MQTTClient(make_client_id(), BROKER_IP)
    client.connect()

    try:
        while True:
            temp_c = read_temperature_c()
            payload = ("%.2f" % temp_c).encode()
            client.publish(TOPIC_TEMP, payload)
            time.sleep(PUBLISH_INTERVAL_S)
    finally:
        try:
            client.disconnect()
        except Exception:
            pass


main()